+        HealingAction::IgnoreDoubleFree
+        | HealingAction::IgnoreForeignFree
+        | HealingAction::ReturnSafeDefault
+        | HealingAction::UpgradeToSafeVariant
+        | HealingAction::None => "{}".to_string(),
